export const INSTANCE_STRIDE_BYTES = 20
export const INSTANCE_STRIDE_F32 = 5

export const FIELD_OFFSET_BYTES = {
  x1: 0,
  x2: 4,
  colorType: 8,
  shapeType: 12,
  yBp: 16,
} as const

export const FIELD_OFFSET_F32 = {
  x1: 0,
  x2: 1,
  colorType: 2,
  shapeType: 3,
  yBp: 4,
} as const

export const GL_ATTRIBUTES: readonly GlAttributeLayout[] = [
  { name: 'a_x1', components: 1, type: 'uint', offsetBytes: 0, integer: true },
  { name: 'a_x2', components: 1, type: 'uint', offsetBytes: 4, integer: true },
  { name: 'a_colorType', components: 1, type: 'float', offsetBytes: 8, integer: false },
  { name: 'a_shapeType', components: 1, type: 'float', offsetBytes: 12, integer: false },
  { name: 'a_yBp', components: 1, type: 'uint', offsetBytes: 16, integer: true },
]

export interface Instance {
  x1: number
  x2: number
  colorType: number
  shapeType: number
  yBp: number
}

export function writeInstance(buf: ArrayBuffer, instanceIndex: number, inst: Instance) {
  const base = instanceIndex * 20
  const dv = new DataView(buf)
  dv.setUint32(base + 0, inst.x1, true)
  dv.setUint32(base + 4, inst.x2, true)
  dv.setFloat32(base + 8, inst.colorType, true)
  dv.setFloat32(base + 12, inst.shapeType, true)
  dv.setUint32(base + 16, inst.yBp, true)
}
